/**
 * event
 * @name onpageload
 * @description
 */
scwin.onpageload = function () {
  scwin.strCurDate = $c.date.getServerDateTime($p, "yyyyMMdd");
  scwin.strPreDate = $c.date.addDate($p, scwin.strCurDate, -2);
};

/**
 * event
 * @name onUdcCompleted
 * @description
 */
scwin.onUdcCompleted = function () {
  let param = $c.data.getParameter($p);
  scwin.v_hhio = param?.hhio ?? param?.menuInfo?.menuParam?.hhio;
  scwin.f_set("ONLOAD");
  acb_cnd_hhbltype.setSelectedIndex(0);
  scwin.f_dateLoading();
};

/**
 * event
 * @name f_set
 * @description 화면 open시 초기 데이타 setting
 */
scwin.f_set = function (gubun) {
  switch (gubun) {
    case "ONLOAD":
      $c.gus.cfDisableKey($p);
      ica_cnd_hhetdFrom.setValue(scwin.strPreDate);
      ica_cnd_hhetdTo.setValue(scwin.strCurDate);
      rd_cnd_hhio.setValue(scwin.v_hhio);
      ed_cnd_hhblno.focus();
      break;
    case "RETRIEVE":
      $c.gus.cfEnableAllBtn($p);
      break;
    case "DELETE":
      $c.gus.cfDisableBtn($p);
      break;
  }
};

/**
 * event
 * @name f_Retrieve
 * @description 조회
 */
scwin.f_Retrieve = async function () {
  // VALIDATE
  if (!(await $c.gus.cfValidate($p, [ica_cnd_hhetdFrom, ica_cnd_hhetdTo, ica_cnd_hhetaFrom, ica_cnd_hhetaTo]))) {
    //validExp 가 yes일때 check
    return;
  }
  if (rd_cnd_hhio.getValue() == "O") {
    // 날짜 범위 확인
    if (!$c.gus.cfIsAfterDate($p, ica_cnd_hhetdFrom.getValue(), ica_cnd_hhetdTo.getValue())) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_048, new Array("ETD From", "ETD To")); //@은(는) 보다 작아야 합니다.
      ica_cnd_hhetdFrom.focus();
      return false;
    }
  } else {
    if (!$c.gus.cfIsAfterDate($p, ica_cnd_hhetaFrom.getValue(), ica_cnd_hhetaTo.getValue())) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_048, new Array("ETA From", "ETA To")); //@은(는) 보다 작아야 합니다.
      ica_cnd_hhetaFrom.focus();
      return false;
    }
  }
  dma_retrieve.set("kcomcd", scwin.hd_kcomcd);

  // item 검색 대소문자 구분 없이 되게끔.
  if (ed_cnd_item.getValue() != "" || ed_cnd_item.getValue() != null) {
    dma_retrieve.set("hhmitem2", dma_retrieve.get("hhmitem2").toUpperCase());
  }
  $c.sbm.execute($p, sbm_retrieve);
};

/**
 * event
 * @name f_FieldClear
 * @description 조회 조건 지우기
 */
scwin.f_FieldClear = function () {
  $c.gus.cfInitObjects($p, tb_searchCondition); // 조회조건의 테이블을 초기화.
  scwin.f_set("ONLOAD");
};

