/**
 * event
 * @name f_downExcelSheet
 * @description 엑셀다운로드
 */
scwin.f_downExcelSheet = async function () {
  if (ds_houseblList.getRowCount()) {
    let cfrm = await $c.win.confirm($p, "House B/L List를 EXCEL로 다운로드 받으시겠습니까?");
    if (cfrm) {
      let sheetTitle = "House BL List"; // '/'있으면 저장안됨.
      // $c.gus.cfGridToExcel(gr_houseblList, sheetTitle, sheetTitle, 1 + 2 + 4 + 8 + 16);
      const options = {
        "fileName": sheetTitle + ".xlsx",
        "sheetName": sheetTitle,
        "hiddenVisible": "true",
        "removeColumns": "0,1,2",
        "colMerge": "true",
        "colMergeTextAlign": "top"
      };
      $c.data.downloadGridViewExcel($p, gr_houseblList, options);
    }
  } else {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다.
  }
};

